import groovy.json.*

def costCentersIDs = testRunner.testCase.testSuite.project.testSuites['GSBet _settlement'].testCases['Create_CC'].testSteps['RunCC_creationIDs'].getPropertyValue('Result')
log.info costCentersIDs

def walletIds1 = costCentersIDs as String
def walletsIds2 = walletIds1.substring(1, walletIds1.length() - 1)
def list = walletsIds2.tokenize(', ')
//log.info list
def check = []
list.each(){ n ->
	testRunner.testCase.testSteps['Properties'].setPropertyValue("costCenterID",n)
	for(i=0;i<1;i++){
     def tc1= testRunner.testCase.testSteps["CreateTerminal"]
     tc1.run(testRunner, context)
     def tc2= testRunner.testCase.testSteps["terminalId"]
     tc2.run(testRunner, context)
     def tc3= testRunner.testCase.testSteps["SetCashPayoutOption"]
     tc3.run(testRunner, context)
      def tc4= testRunner.testCase.testSteps["GetState"]
     tc4.run(testRunner, context)
     def tc5= testRunner.testCase.testSteps["CreateBetshop"]
     tc5.run(testRunner, context)
       Thread.sleep(200);
	}
	check += "'"+n+"'"
}
def check1 = check as String
def check2 = check1.substring(1, check1.length() - 1)
return check2

