con:config.script:
import groovy.json.*
import org.apache.commons.lang.RandomStringUtils 

def val1 = context.expand('${DBcheckTerminal#ResponseAsXml}')
def val2 = new XmlSlurper().parseText(val1)

//log.info val2

def term_Ids = []
//val2.ResultSet.Row.each(){row -> term_Ids.add(row.ID)}
val2.'**'.findAll { node -> node.name() == 'Row' }.each { row ->
    row.'**'.findAll { node -> node.name() == 'TERMINAL.ID' }.each { id ->
        term_Ids.add(id.text())
    }
}

def number = term_Ids.size()
//log.info number

for (i =0; i<number; i++){
		//Collections.shuffle(walletIds)
		def termIDS =  term_Ids[i] as String
		testRunner.testCase.testSteps['Properties'].setPropertyValue("terminalID"+i, termIDS)
}
log.info term_Ids
return term_Ids

import groovy.json.*
import org.apache.commons.lang.RandomStringUtils 

def val1 = context.expand('${DBcheckBetshop#ResponseAsXml}')
def val2 = new XmlSlurper().parseText(val1)

//log.info val2

def term_Ids = []
//val2.ResultSet.Row.each(){row -> term_Ids.add(row.ID)}
val2.'**'.findAll { node -> node.name() == 'Row' }.each { row ->
    row.'**'.findAll { node -> node.name() == 'TERMINAL.ID' }.each { id ->
        term_Ids.add(id.text())
    }
}


def number = term_Ids.size()
//log.info number

for (i =0; i<number; i++){
		//Collections.shuffle(walletIds)
		def termIDS =  term_Ids[i] as String
		testRunner.testCase.testSteps['Properties'].setPropertyValue("betshopID"+i, termIDS)
}
log.info term_Ids
return term_Ids

// === Collect all terminalID0, terminalID1... and save to "Result" ===
def props = testRunner.testCase.testSteps['Properties']

def terminalList = []
def idx = 0

while (true) {
    def propName = "terminalID${idx}"
    def value = props.getPropertyValue(propName)

    if (value == null || value.trim() == "") {
        break
    }

    terminalList << value.trim()
    idx++
}

if (terminalList.size() > 0) {
    def resultValue = terminalList.toString()   // creates [id1, id2, id3, ...]

    props.setPropertyValue("Result", resultValue)
    props.setPropertyValue("AllTerminalIDs", resultValue)

    log.info "✅ SUCCESS: Saved ${terminalList.size()} terminals to Result"
    log.info resultValue
} else {
    log.error "No terminalID properties found!"
}

// === Collect all terminalID0, terminalID1... and save to "Result" ===
def props = testRunner.testCase.testSteps['Properties']

def terminalList = []
def idx = 0

while (true) {
    def propName = "betshopID${idx}"
    def value = props.getPropertyValue(propName)

    if (value == null || value.trim() == "") {
        break
    }

    terminalList << value.trim()
    idx++
}

if (terminalList.size() > 0) {
    def resultValue = terminalList.toString()   // creates [id1, id2, id3, ...]

    props.setPropertyValue("Result", resultValue)
    props.setPropertyValue("AllBetshopIDs", resultValue)

    log.info "✅ SUCCESS: Saved ${terminalList.size()} terminals to Result"
    log.info resultValue
} else {
    log.error "No betshopID properties found!"
}

import groovy.json.JsonSlurper

// Get the Properties step from TerminalCreation test case
def propsStep = testRunner.testCase.testSuite.project
    .testSuites['GSBet _settlement']
    .testCases['TerminalCreation']
    .testSteps['Properties']

// Collect all betshopID* properties dynamically
def betshopIds = []
def i = 0

while (true) {
    def propName = "betshopID${i}"
    def value = propsStep.getPropertyValue(propName)

    if (value == null || value.trim() == "") {
        break  // stop when no more properties
    }

    betshopIds << value.trim()
    i++
}

log.info("Found ${betshopIds.size()} betshop IDs: ${betshopIds}")

// Get current index from local Properties step
def indexProp = testRunner.testCase.testSteps['Properties'].getPropertyValue("i")
if (indexProp == null) {
    log.error("Property 'i' not found or is null")
    return
}

def idx = indexProp as Integer

if (idx < 0 || idx >= betshopIds.size()) {
    log.error("Index ${idx} is out of bounds. Available: 0 to ${betshopIds.size()-1}")
    return
}

// Set the BetshopWalletId
testRunner.testCase.testSteps['Properties'].setPropertyValue("BetshopWalletId", betshopIds[idx])

log.info("Set BetshopWalletId = ${betshopIds[idx]} (index ${idx})")
